    `const __rc = await script.require(${JSON.stringify(a.runtimeLib)});`,
    `const __risu = await __rc.makeRisuTriggerRuntime(api, data, script, ${rtOpts});`,
    `try {`,
    bodyText,
    `} finally {`,
    `  await __risu.flush();`,
    `}`
