// src/util/safe-log.ts
function getSpindle() {
  try {
    return globalThis.spindle;
  } catch {
    return;
  }
}
function consoleFor(level) {
  if (level === "error")
    return (m) => {
      try {
        console.error(m);
      } catch {}
    };
  if (level === "warn")
    return (m) => {
      try {
        console.warn(m);
      } catch {}
    };
  return (m) => {
    try {
      console.log(m);
    } catch {}
  };
}
function spindleChannel(level) {
  if (level === "error")
    return "error";
  if (level === "warn")
    return "warn";
  return "info";
}
function makeSafeLogger(prefix) {
  function emit(level, msg) {
    const line3 = `[lumirealm] ${prefix}: ${msg}`;
    const consoleEmit = level === "error" || logStore.shouldEmit(level);
    if (consoleEmit) {
      const ch = spindleChannel(level);
      const sp = getSpindle();
      const fn = sp?.log?.[ch];
      if (fn) {
        try {
          fn(line3);
        } catch {
          consoleFor(ch)(line3);
        }
      } else {
        consoleFor(ch)(line3);
      }
    }
    logStore.push(level, prefix, msg);
  }
  return {
    error: (m) => emit("error", m),
    warn: (m) => emit("warn", m),
    info: (m) => emit("info", m),
    debug: (m) => emit("debug", m),
    trace: (m) => emit("trace", m)
  };
}

