      characterId,
      characterName: fetched.character.name,
      data: fetched.data,
      creatorNotes: fetched.character.creator_notes ?? "",
      worldBooks,
      fetchWarnings,
      translatedCommentBySourceHash,
      translatedGroupNameByWbId,
      moduleIdByWbId
