    rverbose(`START ctx varsCache_keys=${Object.keys(varsCache).length} messagesCache_count=${messagesCache.length} lorebook_entries=${lorebook.entries.length}`);
    rverbose(`luaOpts=${JSON.stringify(luaOpts ?? {})}`);
